'use client';

import { useState, useEffect } from 'react';
import { Plus, Search, Filter, Grid, List, User, MapPin, Shield, X, Eye } from 'lucide-react';
import { patientApi, type Patient } from '@/lib/api';
import AddPatientModal from './AddPatientModal';
import PatientDetailModal from './PatientDetailModal';

export default function PatientsView() {
  const [patients, setPatients] = useState<Patient[]>([]);
  const [filteredPatients, setFilteredPatients] = useState<Patient[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');
  const [showAddModal, setShowAddModal] = useState(false);
  const [showFilters, setShowFilters] = useState(false);
  const [selectedPatient, setSelectedPatient] = useState<Patient | null>(null);
  const [showDetailModal, setShowDetailModal] = useState(false);

  // Filters
  const [safetyFilter, setSafetyFilter] = useState<string | null>(null);
  const [diagnosisFilter, setDiagnosisFilter] = useState<string | null>(null);

  const fetchPatients = async () => {
    setIsLoading(true);
    try {
      const data = await patientApi.getAll();
      setPatients(data);
      setFilteredPatients(data);
      setError(null);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to fetch patients');
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchPatients();
  }, []);

  useEffect(() => {
    let result = patients;

    // Apply search filter
    if (searchQuery) {
      const query = searchQuery.toLowerCase();
      result = result.filter(
        (p) =>
          p.name.toLowerCase().includes(query) ||
          p.diagnosis.toLowerCase().includes(query) ||
          p.location.toLowerCase().includes(query)
      );
    }

    // Apply safety status filter
    if (safetyFilter) {
      result = result.filter((p) => p.safety_status === safetyFilter);
    }

    // Apply diagnosis filter
    if (diagnosisFilter) {
      result = result.filter((p) => p.diagnosis === diagnosisFilter);
    }

    setFilteredPatients(result);
  }, [searchQuery, patients, safetyFilter, diagnosisFilter]);

  const clearFilters = () => {
    setSearchQuery('');
    setSafetyFilter(null);
    setDiagnosisFilter(null);
  };

  const getSafetyBadge = (status: string) => {
    const styles = {
      safe: 'bg-green-100 text-green-800 border-green-200',
      warning: 'bg-yellow-100 text-yellow-800 border-yellow-200',
      danger: 'bg-red-100 text-red-800 border-red-200',
    };
    return styles[status as keyof typeof styles] || styles.safe;
  };

  const getUniqueValues = (key: keyof Patient) => {
    return [...new Set(patients.map((p) => p[key]))];
  };

  const handleViewPatient = (patient: Patient) => {
    setSelectedPatient(patient);
    setShowDetailModal(true);
  };

  if (isLoading) {
    return (
      <div className="p-8 h-full overflow-auto bg-gray-50 flex items-center justify-center">
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-purple-600 mx-auto mb-4"></div>
          <p className="text-gray-600">Loading patients...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="p-8 h-full overflow-auto bg-gray-50">
      {/* Header */}
      <div className="flex items-center justify-between mb-8">
        <div>
          <h1 className="text-3xl font-bold text-gray-900">Patients</h1>
          <p className="text-gray-600 mt-1">Manage and monitor your patients</p>
        </div>
        <button
          onClick={() => setShowAddModal(true)}
          className="flex items-center gap-2 bg-purple-600 text-white px-6 py-3 rounded-lg hover:bg-purple-700 transition-colors font-semibold"
        >
          <Plus size={20} />
          Add Patient
        </button>
      </div>

      {/* Search and Filters */}
      <div className="flex items-center gap-4 mb-6">
        <div className="flex-1 relative">
          <Search className="absolute left-4 top-1/2 transform -translate-y-1/2 text-gray-400" size={20} />
          <input
            type="text"
            placeholder="Search patients by name, diagnosis, or location..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="w-full pl-12 pr-4 py-3 bg-white border border-gray-200 rounded-lg focus:outline-none focus:border-purple-400 transition-colors"
          />
          {searchQuery && (
            <button
              onClick={() => setSearchQuery('')}
              className="absolute right-4 top-1/2 transform -translate-y-1/2 text-gray-400 hover:text-gray-600"
            >
              <X size={18} />
            </button>
          )}
        </div>
        <div className="relative">
          <button
            onClick={() => setShowFilters(!showFilters)}
            className={`flex items-center gap-2 px-4 py-3 bg-white border border-gray-200 rounded-lg hover:bg-gray-50 transition-colors ${
              (safetyFilter || diagnosisFilter) ? 'border-purple-400 bg-purple-50' : ''
            }`}
          >
            <Filter size={20} className="text-gray-600" />
            <span className="text-gray-700 font-medium">Filters</span>
            {(safetyFilter || diagnosisFilter) && (
              <span className="bg-purple-600 text-white text-xs rounded-full px-2 py-0.5">
                {[safetyFilter, diagnosisFilter].filter(Boolean).length}
              </span>
            )}
          </button>

          {/* Filter Dropdown */}
          {showFilters && (
            <div className="absolute top-full right-0 mt-2 w-64 bg-white border border-gray-200 rounded-lg shadow-lg z-10 p-4">
              <div className="space-y-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">Safety Status</label>
                  <select
                    value={safetyFilter || ''}
                    onChange={(e) => setSafetyFilter(e.target.value || null)}
                    className="w-full px-3 py-2 border border-gray-200 rounded-lg focus:outline-none focus:border-purple-400"
                  >
                    <option value="">All</option>
                    <option value="safe">Safe</option>
                    <option value="warning">Warning</option>
                    <option value="danger">Danger</option>
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">Diagnosis</label>
                  <select
                    value={diagnosisFilter || ''}
                    onChange={(e) => setDiagnosisFilter(e.target.value || null)}
                    className="w-full px-3 py-2 border border-gray-200 rounded-lg focus:outline-none focus:border-purple-400"
                  >
                    <option value="">All</option>
                    {getUniqueValues('diagnosis').map((diagnosis) => (
                      <option key={diagnosis as string} value={diagnosis as string}>
                        {diagnosis as string}
                      </option>
                    ))}
                  </select>
                </div>
                <button
                  onClick={() => {
                    setSafetyFilter(null);
                    setDiagnosisFilter(null);
                  }}
                  className="w-full text-sm text-purple-600 hover:text-purple-700"
                >
                  Clear Filters
                </button>
              </div>
            </div>
          )}
        </div>
        <div className="flex items-center gap-2 bg-white border border-gray-200 rounded-lg p-1">
          <button
            onClick={() => setViewMode('grid')}
            className={`p-2 rounded-md transition-colors ${
              viewMode === 'grid' ? 'bg-purple-600 text-white' : 'text-gray-600 hover:bg-gray-100'
            }`}
          >
            <Grid size={20} />
          </button>
          <button
            onClick={() => setViewMode('list')}
            className={`p-2 rounded-md transition-colors ${
              viewMode === 'list' ? 'bg-purple-600 text-white' : 'text-gray-600 hover:bg-gray-100'
            }`}
          >
            <List size={20} />
          </button>
        </div>
      </div>

      {/* Error State */}
      {error && (
        <div className="bg-red-50 border border-red-200 text-red-700 px-4 py-3 rounded-lg mb-6">
          {error}
          <button
            onClick={fetchPatients}
            className="ml-4 underline hover:no-underline"
          >
            Retry
          </button>
        </div>
      )}

      {/* Patient Count */}
      <p className="text-gray-600 mb-6">
        Showing {filteredPatients.length} of {patients.length} patients
      </p>

      {/* Patient Grid/List */}
      {filteredPatients.length > 0 ? (
        viewMode === 'grid' ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {filteredPatients.map((patient) => (
              <div
                key={patient.id}
                className="bg-white rounded-xl shadow-sm border border-gray-100 p-6 hover:shadow-md transition-shadow cursor-pointer"
                onClick={() => handleViewPatient(patient)}
              >
                <div className="flex items-start justify-between mb-4">
                  <div className="flex items-center gap-3">
                    <div className="w-12 h-12 bg-purple-100 rounded-full flex items-center justify-center">
                      <User size={24} className="text-purple-600" />
                    </div>
                    <div>
                      <h3 className="font-semibold text-gray-900">{patient.name}</h3>
                      <p className="text-sm text-gray-500">{patient.age} years old</p>
                    </div>
                  </div>
                  <span
                    className={`px-2 py-1 text-xs font-medium rounded-full border ${getSafetyBadge(
                      patient.safety_status
                    )}`}
                  >
                    {patient.safety_status}
                  </span>
                </div>

                <div className="space-y-2">
                  <div className="flex items-center gap-2 text-sm text-gray-600">
                    <Shield size={16} className="text-gray-400" />
                    <span>{patient.diagnosis}</span>
                  </div>
                  <div className="flex items-center gap-2 text-sm text-gray-600">
                    <MapPin size={16} className="text-gray-400" />
                    <span>{patient.location}</span>
                  </div>
                </div>

                {patient.medications && patient.medications.length > 0 && (
                  <div className="mt-4 pt-4 border-t border-gray-100">
                    <p className="text-xs text-gray-500 mb-2">Medications</p>
                    <div className="flex flex-wrap gap-1">
                      {patient.medications.slice(0, 3).map((med) => (
                        <span
                          key={med.id}
                          className="px-2 py-1 bg-blue-50 text-blue-700 text-xs rounded-full"
                        >
                          {med.name}
                        </span>
                      ))}
                      {patient.medications.length > 3 && (
                        <span className="px-2 py-1 bg-gray-100 text-gray-600 text-xs rounded-full">
                          +{patient.medications.length - 3} more
                        </span>
                      )}
                    </div>
                  </div>
                )}

                <button
                  onClick={(e) => {
                    e.stopPropagation();
                    handleViewPatient(patient);
                  }}
                  className="mt-4 w-full flex items-center justify-center gap-2 py-2 bg-gray-50 hover:bg-gray-100 rounded-lg text-sm text-gray-700 transition-colors"
                >
                  <Eye size={16} />
                  View Details
                </button>
              </div>
            ))}
          </div>
        ) : (
          <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
            <table className="w-full">
              <thead className="bg-gray-50 border-b border-gray-100">
                <tr>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Patient
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Diagnosis
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Location
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Status
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Actions
                  </th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-100">
                {filteredPatients.map((patient) => (
                  <tr
                    key={patient.id}
                    className="hover:bg-gray-50 cursor-pointer"
                    onClick={() => handleViewPatient(patient)}
                  >
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="flex items-center gap-3">
                        <div className="w-10 h-10 bg-purple-100 rounded-full flex items-center justify-center">
                          <User size={20} className="text-purple-600" />
                        </div>
                        <div>
                          <p className="font-medium text-gray-900">{patient.name}</p>
                          <p className="text-sm text-gray-500">{patient.age} years old</p>
                        </div>
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-600">
                      {patient.diagnosis}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-600">
                      {patient.location}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <span
                        className={`px-2 py-1 text-xs font-medium rounded-full border ${getSafetyBadge(
                          patient.safety_status
                        )}`}
                      >
                        {patient.safety_status}
                      </span>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <button
                        onClick={(e) => {
                          e.stopPropagation();
                          handleViewPatient(patient);
                        }}
                        className="text-purple-600 hover:text-purple-700 text-sm font-medium"
                      >
                        View Details
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )
      ) : (
        <div className="flex flex-col items-center justify-center py-20">
          <div className="w-20 h-20 bg-gray-100 rounded-full flex items-center justify-center mb-4">
            <User size={40} className="text-gray-400" />
          </div>
          <p className="text-gray-500 text-lg mb-2">
            {patients.length === 0 ? 'No patients yet' : 'No patients found'}
          </p>
          <p className="text-gray-400 text-sm mb-6">
            {patients.length === 0
              ? 'Add your first patient to get started'
              : 'Try adjusting your search or filters'}
          </p>
          {(searchQuery || safetyFilter || diagnosisFilter) ? (
            <button
              onClick={clearFilters}
              className="px-6 py-2 bg-white border border-gray-300 rounded-lg text-gray-700 hover:bg-gray-50 transition-colors"
            >
              Clear search
            </button>
          ) : (
            <button
              onClick={() => setShowAddModal(true)}
              className="px-6 py-3 bg-purple-600 text-white rounded-lg hover:bg-purple-700 transition-colors font-medium"
            >
              Add First Patient
            </button>
          )}
        </div>
      )}

      {/* Add Patient Modal */}
      <AddPatientModal
        open={showAddModal}
        onOpenChange={setShowAddModal}
        onSuccess={fetchPatients}
      />

      {/* Patient Detail Modal */}
      {selectedPatient && (
        <PatientDetailModal
          open={showDetailModal}
          onOpenChange={setShowDetailModal}
          patient={selectedPatient}
          onUpdate={fetchPatients}
        />
      )}
    </div>
  );
}
